# Summarizes a user's comment flagging standing for the standing.json endpoint.
class UserStandingSummary
  def initialize(user)
    @user = user
  end

  def n_comments
    @user.comments.count
  end

  def n_flagged_comments
    @user.comments.where(comments: {flags: 1..}).count
  end

  def n_flags
    @user.comments.sum(:flags)
  end

  def as_json(*)
    {
      username: @user.username,
      n_comments: n_comments,
      n_flagged_comments: n_flagged_comments,
      n_flags: n_flags
    }
  end
end

